// marked.min.js (enhanced TS-safe Markdown renderer)

(function () {
    function escapeHtml(str) {
        return str
            .replace(/&/g, "&amp;")
            .replace(/</g, "&lt;")
            .replace(/>/g, "&gt;");
    }

    function renderInline(md) {
        let html = escapeHtml(md);

        // Images: ![alt](url)
        html = html.replace(
            new RegExp("!\
\\(([^)]+)\\)", "g"),
            '<img alt="$1" src="$2">'
        );

        // Links: [text](url)
        html = html.replace(
            new RegExp("\
\[([^\
\\(([^)]+)\\)", "g"),
            '<a href="$2" target="_blank" rel="noopener">$1</a>'
        );

        // Inline code: `code`
        html = html.replace(
            new RegExp("`([^`]+)`", "g"),
            "<code>$1</code>"
        );

        // Bold
        html = html.replace(
            new RegExp("\\*\\*([^*]+)\\*\\*", "g"),
            "<strong>$1</strong>"
        );
        html = html.replace(
            new RegExp("__(.+?)__", "g"),
            "<strong>$1</strong>"
        );

        // Italic
        html = html.replace(
            new RegExp("\\*([^*]+)\\*", "g"),
            "<em>$1</em>"
        );
        html = html.replace(
            new RegExp("_([^_]+)_", "g"),
            "<em>$1</em>"
        );

        return html;
    }

    function marked(md) {
        if (!md) return "";

        const lines = md.split(/\r?\n/);
        const out = [];

        let inList = false;
        let inOrderedList = false;
        let inCodeBlock = false;
        let codeBuffer = [];

        function closeLists() {
            if (inList) {
                out.push("</ul>");
                inList = false;
            }
            if (inOrderedList) {
                out.push("</ol>");
                inOrderedList = false;
            }
        }

        function closeCodeBlock() {
            if (inCodeBlock) {
                out.push("<pre><code>" + escapeHtml(codeBuffer.join("\n")) + "</code></pre>");
                inCodeBlock = false;
                codeBuffer = [];
            }
        }

        const reFence = new RegExp("^```");
        const reHr = new RegExp("^(?:\\*\\*\\*|---|___)\\s*$");
        const reQuote = new RegExp("^>\\s?(.*)$");
        const reHeading = new RegExp("^(#{1,6})\\s+(.*)$");
        const reOrdered = new RegExp("^\\s*\\d+\\.\\s+(.*)$");
        const reUnordered = new RegExp("^\\s*[-*+]\\s+(.*)$");
        const reBlank = new RegExp("^\\s*$");

        for (let line of lines) {
            // Fenced code block ```
            if (reFence.test(line)) {
                if (inCodeBlock) {
                    closeCodeBlock();
                } else {
                    closeLists();
                    inCodeBlock = true;
                }
                continue;
            }

            if (inCodeBlock) {
                codeBuffer.push(line);
                continue;
            }

            // Horizontal rule
            if (reHr.test(line)) {
                closeLists();
                out.push("<hr>");
                continue;
            }

            // Blockquote
            const quoteMatch = line.match(reQuote);
            if (quoteMatch) {
                closeLists();
                out.push("<blockquote>" + renderInline(quoteMatch[1]) + "</blockquote>");
                continue;
            }

            // Headings
            const headingMatch = line.match(reHeading);
            if (headingMatch) {
                closeLists();
                const level = headingMatch[1].length;
                out.push("<h" + level + ">" + renderInline(headingMatch[2]) + "</h" + level + ">");
                continue;
            }

            // Ordered list
            const orderedMatch = line.match(reOrdered);
            if (orderedMatch) {
                if (!inOrderedList) {
                    closeLists();
                    out.push("<ol>");
                    inOrderedList = true;
                }
                out.push("<li>" + renderInline(orderedMatch[1]) + "</li>");
                continue;
            }

            // Unordered list
            const listMatch = line.match(reUnordered);
            if (listMatch) {
                if (!inList) {
                    closeLists();
                    out.push("<ul>");
                    inList = true;
                }
                out.push("<li>" + renderInline(listMatch[1]) + "</li>");
                continue;
            }

            // Blank line
            if (reBlank.test(line)) {
                closeLists();
                continue;
            }

            // Paragraph
            closeLists();
            out.push("<p>" + renderInline(line) + "</p>");
        }

        closeCodeBlock();
        closeLists();

        return out.join("\n");
    }

    window.marked = marked;
})();
